SET NAMES utf8mb4;
USE interview_db;

INSERT INTO questions (question, model_answer, category) VALUES
-- ==========================================
-- 1. 네트워크(1계층) - 물리 계층
-- ==========================================
('OSI 7계층 중 1계층(물리 계층)의 주요 역할은 무엇인가요?', '데이터(0과 1의 비트열)를 전기적, 광학적 신호로 변환하여 통신 케이블 등의 물리적 매체를 통해 전송하는 역할을 합니다.', '네트워크(1계층)'),
('1계층에서 데이터를 전송하는 단위(PDU)는 무엇인가요?', '1계층의 데이터 전송 단위는 비트(Bit)입니다. 전기 신호의 On/Off 상태를 의미합니다.', '네트워크(1계층)'),
('리피터(Repeater)의 역할은 무엇인가요?', '물리적 매체를 통해 전송되면서 약해진 전기 신호를 증폭시키고 재생하여 전송 거리를 연장해 주는 1계층 장비입니다.', '네트워크(1계층)'),
('허브(Hub)의 동작 방식과 단점은 무엇인가요?', '허브는 수신한 신호를 연결된 모든 포트로 브로드캐스트(플러딩)합니다. 목적지를 구별하지 못해 충돌(Collision)이 자주 발생하고 네트워크 대역폭이 낭비됩니다.', '네트워크(1계층)'),
('더미 허브와 스위칭 허브의 차이점은 무엇인가요?', '더미 허브는 1계층 장비로 단순 신호 증폭 및 전체 브로드캐스트만 수행하지만, 스위칭 허브(L2 스위치)는 2계층 장비로 MAC 주소를 인식해 목적지에만 유니캐스트 통신을 합니다.', '네트워크(1계층)'),
('UTP 케이블과 STP 케이블의 차이는 무엇인가요?', 'UTP는 쉴드(보호막)가 없는 꼬임선으로 가격이 저렴해 일반 LAN 환경에 쓰이며, STP는 내부 쉴드가 있어 전자기 간섭(EMI)을 막아주어 노이즈가 심한 공장 등에서 사용됩니다.', '네트워크(1계층)'),
('네트워크 토폴로지 중 스타(Star) 토폴로지의 장단점은?', '중앙의 허브나 스위치에 모든 노드가 연결된 형태입니다. 노드 추가/삭제가 쉽고 특정 노드 장애가 전체에 영향을 주지 않지만, 중앙 장비(스위치) 장애 시 전체 네트워크가 마비됩니다.', '네트워크(1계층)'),
('망형(Mesh) 토폴로지의 특징은 무엇인가요?', '모든 노드가 서로 1:1로 연결된 형태입니다. 특정 회선에 장애가 발생해도 우회 경로가 있어 가용성이 매우 높지만, 케이블 구축 비용이 가장 비쌉니다.', '네트워크(1계층)'),
('베이스밴드(Baseband)와 브로드밴드(Broadband) 전송의 차이는?', '베이스밴드는 디지털 신호를 변조 없이 직접 전송하며 주로 LAN에서 씁니다. 브로드밴드는 신호를 아날로그로 변조해 여러 주파수 대역으로 분할 전송하며 장거리 통신(WAN)에 쓰입니다.', '네트워크(1계층)'),
('네트워크 트러블슈팅 시 1계층(물리 계층)에서 주로 확인하는 장애 요인은?', '랜 케이블의 단선, 커넥터(RJ-45) 접촉 불량, 포트의 물리적 손상, 장비 전원 꺼짐 등 물리적 연결 상태를 가장 먼저 점검합니다.', '네트워크(1계층)'),
('NIC(Network Interface Card)는 OSI 몇 계층 장비인가요?', '물리적인 신호 변환을 수행하므로 1계층에 속하면서, 동시에 고유한 MAC 주소를 가지고 프레임을 처리하므로 2계층(데이터링크 계층)에도 속하는 장비입니다.', '네트워크(1계층)'),
('CSMA/CD에서 충돌 감지(Collision Detection)는 주로 어느 계층에서 물리적으로 감지하나요?', '충돌 감지 자체는 케이블 상의 전압 변화를 통해 1계층(물리 계층)에서 이루어지며, 이후 백오프 알고리즘 등 제어는 2계층(MAC 하위 계층)에서 처리됩니다.', '네트워크(1계층)'),

-- ==========================================
-- 2. 네트워크(2계층) - 데이터 링크 계층
-- ==========================================
('2계층(데이터 링크 계층)의 주요 역할은 무엇인가요?', '직접 연결된 인접 노드 간의 신뢰성 있는 데이터 전송을 담당합니다. 물리적 주소(MAC)를 사용하며 오류 제어와 흐름 제어를 수행합니다.', '네트워크(2계층)'),
('2계층의 데이터 전송 단위(PDU)는 무엇인가요?', '프레임(Frame)입니다. 패킷에 MAC 헤더와 오류 검출을 위한 트레일러(FCS)가 붙은 형태입니다.', '네트워크(2계층)'),
('MAC 주소(Media Access Control Address)란 무엇인가요?', '네트워크 인터페이스 카드(NIC)에 제조 시 물리적으로 할당되는 48비트의 고유 식별 주소입니다. 앞 24비트는 제조사(OUI), 뒤 24비트는 일련번호를 나타냅니다.', '네트워크(2계층)'),
('스위치(Switch)의 핵심 동작 원리는 무엇인가요?', '스위치는 수신된 프레임의 출발지 MAC 주소를 학습하여 CAM 테이블에 기록하고, 목적지 MAC 주소를 확인해 해당 포트로만 프레임을 포워딩(유니캐스트)합니다.', '네트워크(2계층)'),
('스위치의 플러딩(Flooding) 현상이란 무엇인가요?', '스위치의 CAM 테이블에 목적지 MAC 주소가 없을 때, 프레임을 수신한 포트를 제외한 모든 포트로 데이터를 브로드캐스트하여 목적지를 찾는 과정입니다.', '네트워크(2계층)'),
('CSMA/CD 방식에 대해 설명해주세요.', '유선 LAN 환경에서 채널이 비어있는지 확인(CS)하고 데이터를 전송(MA)하며, 동시에 전송해 충돌이 발생하면 이를 감지(CD)해 잼 신호를 보내고 임의의 시간 대기 후 재전송하는 기법입니다.', '네트워크(2계층)'),
('브로드캐스트 스톰(Broadcast Storm)이란 무엇인가요?', '스위치 간 이중화 연결 구조에서 논리적 루프가 발생하여, 브로드캐스트 프레임이 무한히 네트워크를 맴돌며 대역폭을 고갈시키고 장비를 마비시키는 현상입니다.', '네트워크(2계층)'),
('STP(Spanning Tree Protocol)의 역할은 무엇인가요?', '스위치 이중화로 인한 물리적 루프를 방지하기 위해, 특정 포트를 논리적으로 차단(Blocking)하여 트리 구조를 만들고 루핑과 브로드캐스트 스톰을 사전에 차단하는 2계층 프로토콜입니다.', '네트워크(2계층)'),
('VLAN(Virtual LAN)의 도입 목적은 무엇인가요?', '물리적 라우터나 스위치의 추가 증설 없이 하나의 스위치를 논리적으로 분할하여, 브로드캐스트 도메인을 축소해 네트워크 성능을 높이고 부서별 보안 격리를 달성하기 위함입니다.', '네트워크(2계층)'),
('FCS(Frame Check Sequence)란 무엇인가요?', '프레임의 꼬리(트레일러) 부분에 붙는 값으로, 데이터 전송 중 노이즈 등으로 인해 프레임에 물리적 오류가 발생했는지 수신 측에서 검증(CRC 알고리즘)하는 역할을 합니다.', '네트워크(2계층)'),
('브리지(Bridge)와 2계층 스위치의 차이점은 무엇인가요?', '두 장비 모두 MAC 기반으로 동작하지만, 브리지는 소프트웨어 기반 처리로 속도가 느리고 포트 수가 적은 반면, 스위치는 ASIC 하드웨어 칩 기반으로 처리 속도가 훨씬 빠르고 포트 수가 많습니다.', '네트워크(2계층)'),

-- ==========================================
-- 3. 네트워크(3계층) - 네트워크 계층
-- ==========================================
('3계층(네트워크 계층)의 주요 역할은 무엇인가요?', '다양한 네트워크를 거쳐 출발지에서 최종 목적지까지 데이터를 안전하고 빠르게 전달하기 위해 논리적 주소(IP)를 할당하고 최적의 경로를 찾는 라우팅(Routing)을 수행합니다.', '네트워크(3계층)'),
('3계층의 데이터 전송 단위(PDU)는 무엇인가요?', '패킷(Packet)입니다. 상위 계층의 세그먼트에 발신지 및 목적지 IP 주소가 포함된 IP 헤더가 붙은 형태입니다.', '네트워크(3계층)'),
('IP 주소의 특징과 MAC 주소와의 차이점은?', 'MAC은 하드웨어에 고정된 물리적 주소로 인접 노드 간(LAN) 통신에 쓰이지만, IP 주소는 네트워크 관리자가 할당하는 논리적 주소로 서로 다른 네트워크 간(WAN) 최종 목적지를 찾아갈 때 쓰입니다.', '네트워크(3계층)'),
('라우터(Router)의 역할과 라우팅 테이블(Routing Table)은 무엇인가요?', '라우터는 3계층 장비로 IP 패킷의 경로를 결정합니다. 라우팅 테이블은 네트워크 대역(목적지)과 그곳으로 가기 위한 다음 홉(Next Hop) 및 인터페이스 정보를 매핑해둔 지도 역할을 합니다.', '네트워크(3계층)'),
('게이트웨이(Gateway)란 무엇인가요?', '현재 호스트가 속한 내부 네트워크 대역을 벗어나 외부 인터넷(다른 대역)으로 패킷을 보낼 때, 이를 내보내 주는 첫 번째 라우터의 인터페이스 IP(관문)를 의미합니다.', '네트워크(3계층)'),
('서브넷 마스크(Subnet Mask)의 목적은 무엇인가요?', 'IP 주소 체계에서 어디까지가 속한 네트워크(Network ID) 영역이고, 어디부터가 특정 기기를 식별하는 호스트(Host ID) 영역인지 논리적 비트 연산(AND)을 통해 구분하기 위함입니다.', '네트워크(3계층)'),
('CIDR(Classless Inter-Domain Routing) 방식이란?', '과거 A, B, C 클래스 방식의 고정된 IP 할당으로 인한 심각한 IP 낭비를 막기 위해, 슬래시(/24 등) 표기법을 통해 필요한 비트 단위만큼 유연하게 서브넷 대역을 쪼개는 방식입니다.', '네트워크(3계층)'),
('공인 IP와 사설 IP, 그리고 NAT의 관계를 설명해주세요.', '사설 IP는 내부망(공유기 하위)에서 무료로 쓰는 주소이며 직접 인터넷 통신이 불가합니다. NAT 장비(라우터)가 통신 시 이 사설 IP를 외부에서 식별 가능한 공인 IP로 변환해주어 IP 절약과 보안을 달성합니다.', '네트워크(3계층)'),
('OSPF 라우팅 프로토콜의 특징은?', '회사 내부망(단일 AS)에서 주로 쓰는 IGP(내부 게이트웨이 프로토콜)로, 홉 카운트뿐만 아니라 회선의 대역폭(속도) 상태를 종합적으로 계산하여 가장 빠른 최적 경로를 찾습니다.', '네트워크(3계층)'),
('BGP 라우팅 프로토콜의 특징은?', '통신사(ISP) 간이나 거대한 글로벌 AS 간에 쓰이는 EGP(외부 게이트웨이 프로토콜)로, 속도보다는 조직 간의 비즈니스 규칙과 트래픽 제어 정책(Policy-based)에 따라 경로를 결정합니다.', '네트워크(3계층)'),
('ICMP(인터넷 제어 메시지 프로토콜)의 역할은?', 'IP 프로토콜은 에러 보고 기능이 없기 때문에 이를 보완하여, 패킷 전송 중 라우터에서 발생한 오류 상태나 목적지 도달 불가 원인을 출발지에 알려주는 역할을 합니다.', '네트워크(3계층)'),
('Ping과 Traceroute의 차이는 무엇인가요?', 'Ping은 ICMP Echo 요청을 보내 대상 서버까지 단순히 살아서 도달하는지(응답 여부와 지연시간)를 점검하며, Traceroute는 패킷의 TTL 값을 1씩 늘려가며 통과하는 모든 라우터 홉(Hop)의 전체 경로와 끊긴 구간을 추적합니다.', '네트워크(3계층)'),

-- ==========================================
-- 4. 네트워크(4계층) - 전송 계층
-- ==========================================
('4계층(전송 계층)의 주요 역할은 무엇인가요?', '종단 간(End-to-End) 애플리케이션 프로세스들이 신뢰성 있게 통신할 수 있도록, 포트(Port) 번호를 통해 프로세스를 식별하고 TCP/UDP를 통해 오류 제어, 흐름 제어, 혼잡 제어를 수행합니다.', '네트워크(4계층)'),
('4계층의 데이터 전송 단위(PDU)는 무엇인가요?', '세그먼트(Segment)입니다. 응용 계층의 데이터에 발신지/목적지 포트 번호, Sequence Number 등이 포함된 TCP/UDP 헤더가 붙은 형태입니다.', '네트워크(4계층)'),
('포트(Port) 번호의 역할은 무엇인가요?', 'IP 주소가 특정 컴퓨터(서버)를 찾아가게 해준다면, 포트 번호는 그 컴퓨터 내부에서 실행 중인 수많은 애플리케이션(웹, DB, SSH 등) 중 정확히 어떤 프로세스에게 데이터를 전달할지 식별해 줍니다.', '네트워크(4계층)'),
('TCP와 UDP의 차이점을 요약해주세요.', 'TCP는 연결 지향적이며 흐름/혼잡 제어를 통해 패킷의 순서와 100% 신뢰성을 보장하지만 오버헤드가 커서 느립니다. UDP는 비연결형으로 신뢰성 검증 없이 마구 전송하여 데이터가 유실될 수 있으나 속도가 매우 빠릅니다.', '네트워크(4계층)'),
('TCP 3-Way Handshake 과정을 설명해주세요.', '통신 전 논리적 연결을 수립하는 과정입니다. 1) 클라이언트가 SYN 패킷(연결 요청)을 보냅니다. 2) 서버가 수락의 의미로 SYN+ACK 패킷을 보냅니다. 3) 클라이언트가 확인의 의미로 ACK 패킷을 보내 연결이 완료됩니다.', '네트워크(4계층)'),
('TCP 4-Way Handshake 과정을 설명해주세요.', '통신을 안전하게 해제하는 과정입니다. 1) 클라이언트가 FIN(종료 요청)을 보냅니다. 2) 서버가 ACK를 보냅니다. 3) 서버가 남은 데이터 처리를 완료한 후 자신의 FIN을 보냅니다. 4) 클라이언트가 확인용 ACK를 보내고 종료합니다.', '네트워크(4계층)'),
('TCP 종료 시 TIME-WAIT 상태를 두는 2가지 이유는?', '첫째, 네트워크 지연으로 서버가 늦게 보낸 데이터 패킷이 연결 종료 후 도착할 경우를 대비해 일정 시간 대기합니다. 둘째, 클라이언트가 보낸 마지막 ACK가 유실되었을 경우 서버가 FIN을 재전송할 수 있도록 연결 상태를 유지하기 위함입니다.', '네트워크(4계층)'),
('초기 Sequence Number(ISN)를 0이 아닌 난수로 설정하는 이유는?', '서버의 포트는 유한하여 재사용되는데, 만약 고정된 순차 번호를 쓰면 과거에 종료된 커넥션에서 뒤늦게 도착한 지연 패킷을 현재 커넥션의 정상 패킷으로 오인하여 데이터가 꼬일 위험이 있기 때문입니다.', '네트워크(4계층)'),
('TCP의 흐름 제어(Flow Control)란 무엇인가요?', '송신 측의 전송 속도가 너무 빨라 수신 측의 버퍼(메모리) 용량을 초과해 패킷이 버려지는 것을 막기 위해, 수신 측이 수용 가능한 윈도우 크기(Window Size)를 알려주어 송수신 속도를 조절하는 기법(슬라이딩 윈도우)입니다.', '네트워크(4계층)'),
('TCP의 혼잡 제어(Congestion Control)란 무엇인가요?', '네트워크 인프라(라우터 등) 내의 데이터 양이 한계를 초과하여 전체 네트워크 마비(오버플로우)가 발생하는 것을 막기 위해, 송신 측 스스로 패킷 발송 양(Congestion Window)을 제어하는 기법입니다.', '네트워크(4계층)'),
('혼잡 제어의 Slow Start 방식과 AIMD 방식은?', 'Slow Start는 패킷 발송량을 1부터 지수 함수적으로 빠르게 늘리다 혼잡 시 1로 확 줄이는 방식이며, AIMD는 선형적으로 서서히 늘리다 혼잡 감지 시 발송량을 절반으로 깎아 제어하는 안정화 방식입니다.', '네트워크(4계층)'),
('netstat 명령어의 역할은 무엇인가요?', '서버에서 현재 열려 있는 리스닝(LISTEN) 포트 목록과 외부 클라이언트와 맺어진 TCP 통신 세션(ESTABLISHED) 상태, 그리고 PID 정보를 확인하여 네트워크 연결 상태를 모니터링하는 필수 명령어입니다.', '네트워크(4계층)'),

-- ==========================================
-- 5. 네트워크(2/3/4계층 공통)
-- ==========================================
('L2 스위치, L3 스위치, L4 스위치의 차이점을 설명해주세요.', 'L2 스위치는 MAC 주소 기반으로 동작합니다. L3 스위치는 L2 기능에 IP 라우팅(3계층) 하드웨어 칩을 더해 고속 라우팅을 수행합니다. L4 스위치는 로드밸런서 역할을 하며 TCP/UDP 포트 번호를 기반으로 트래픽을 분산시킵니다.', '네트워크(2/3/4계층 공통)'),
('로드밸런서에서 L4 로드밸런싱과 L7 로드밸런싱의 차이는?', 'L4 LB는 OSI 4계층(TCP/UDP) 수준에서 IP와 포트 번호만 보고 트래픽을 단순/고속 분산합니다. L7 LB는 응용 계층(HTTP)까지 까보고 URL 경로(Path), 헤더, 쿠키 등 애플리케이션 데이터를 분석해 지능적으로 분산합니다.', '네트워크(2/3/4계층 공통)'),
('캡슐화(Encapsulation) 관점에서 데이터를 내려보낼 때 추가되는 헤더 순서는?', '응용 계층의 Data에 4계층 포트가 담긴 TCP 헤더(Segment)가 붙고, 3계층 출발지/목적지 IP 헤더(Packet)가 붙으며, 마지막으로 2계층 MAC 헤더와 꼬리(FCS)가 붙어 Frame이 되어 1계층 비트로 전송됩니다.', '네트워크(2/3/4계층 공통)'),
('ARP 프로토콜은 2계층과 3계층 중 어디에 속하나요?', 'ARP는 3계층 주소인 IP 주소를 이용해 2계층 주소인 MAC 주소를 알아내는 역할을 하므로, 2계층과 3계층 사이의 논리적 경계에서 두 계층을 연결해 주는 브릿지 역할을 수행한다고 봅니다.', '네트워크(2/3/4계층 공통)'),
('MTU(Maximum Transmission Unit)와 MSS(Maximum Segment Size)의 차이는?', 'MTU는 2/3계층 관점에서 네트워크 인터페이스가 한 번에 전송할 수 있는 최대 패킷 크기(이더넷 기준 보통 1500바이트)이며, MSS는 4계층 관점에서 TCP 헤더와 IP 헤더를 제외하고 실제로 담을 수 있는 순수 데이터의 최대 크기입니다.', '네트워크(2/3/4계층 공통)'),
('네트워크 장애 발생 시 Bottom-Up 트러블슈팅 접근법이란?', '1계층인 물리 케이블/포트 LED부터 시작해, 2계층 MAC 충돌/VLAN 확인, 3계층 IP/Ping 라우팅 점검, 4계층 방화벽 포트 확인, 마지막으로 7계층 앱 로그를 순차적으로 확인하여 원인을 좁혀가는 실무 방식입니다.', '네트워크(2/3/4계층 공통)'),

-- ==========================================
-- 6. 웹/HTTP (7계층)
-- ==========================================
('HTTP 프로토콜의 특징인 Stateless와 Connectionless는 무엇인가요?', 'Stateless는 서버가 클라이언트의 이전 통신 상태(로그인 여부 등)를 저장하지 않는 무상태성입니다. Connectionless는 요청에 대한 응답을 완료하면 즉시 TCP 연결을 끊어버려 서버 자원을 절약하는 특징입니다.', '웹/HTTP'),
('HTTP와 HTTPS의 차이점은 무엇인가요?', 'HTTP는 평문 텍스트로 통신하여 스니핑 시 데이터가 노출됩니다. HTTPS는 HTTP 아래에 SSL/TLS 계층을 두어 데이터를 암호화하여 통신하므로, 패킷이 탈취되더라도 기밀성을 보장합니다.', '웹/HTTP'),
('HTTPS 통신 과정(TLS Handshake)에서 대칭키와 비대칭키는 어떻게 쓰이나요?', '초기 연결 시에는 암호화 강도가 높고 안전한 비대칭키(공개키/개인키) 방식을 통해 세션키를 암호화하여 주고받습니다. 키 교환이 완료된 이후의 실제 대용량 데이터 통신은 처리 속도가 빠른 대칭키 방식으로 암호화합니다.', '웹/HTTP'),
('GET 메서드와 POST 메서드의 차이는 무엇인가요?', 'GET은 데이터를 조회할 때 쓰며 파라미터를 URL(헤더)에 노출시키고 여러 번 호출해도 결과가 동일한 멱등성을 가집니다. POST는 데이터를 생성할 때 쓰며 데이터를 암호화된 Body에 숨겨 보내고 멱등성이 없습니다.', '웹/HTTP'),
('HTTP 상태 코드 200, 301, 401, 403, 500의 의미를 각각 설명해주세요.', '200은 성공, 301은 영구 리다이렉션(URL 변경), 401은 인증 실패(로그인 안 됨), 403은 인가 실패(권한 없음), 500은 서버 내부 로직 오류 및 예외 발생을 의미합니다.', '웹/HTTP'),
('쿠키(Cookie)와 세션(Session)의 차이점은?', '쿠키는 클라이언트(브라우저)에 텍스트 형태로 저장되어 속도가 빠르나 변조 등 보안에 취약합니다. 세션은 민감한 상태 정보를 웹 서버 메모리나 DB에 객체로 저장하므로 안전하지만, 접속자가 많으면 서버 부하가 커집니다.', '웹/HTTP'),
('JWT(토큰) 기반 인증의 장점은 무엇인가요?', '세션처럼 상태 정보를 서버 메모리에 저장(Stateful)할 필요 없이, 인증 정보를 암호화시킨 토큰을 클라이언트에 저장(Stateless)하여 요청 시 헤더에 담아 보냅니다. 따라서 분산 서버(Scale-out) 환경에서 서버 부하를 획기적으로 줄여줍니다.', '웹/HTTP'),
('RESTful API란 무엇인가요?', 'URI를 통해 조작할 자원(Resource)을 명확히 명시하고, HTTP Method(GET/POST/PUT/DELETE)를 이용해 해당 자원에 대한 행위(CRUD)를 정의하는 직관적이고 표준화된 백엔드 API 설계 아키텍처입니다.', '웹/HTTP'),
('CORS(Cross-Origin Resource Sharing)와 SOP의 관계는?', 'SOP는 브라우저가 보안상 다른 도메인(출처)의 리소스 접근을 차단하는 기본 정책입니다. CORS는 프론트엔드와 백엔드 도메인이 다를 때, 백엔드 서버가 허용 헤더(Access-Control-Allow-Origin)를 설정해 SOP 정책을 안전하게 우회하도록 해주는 규약입니다.', '웹/HTTP'),
('CSRF와 XSS 웹 보안 취약점의 차이는 무엇인가요?', 'XSS는 게시판 등에 악성 스크립트를 삽입해 사용자의 브라우저에서 실행되게 하여 세션(쿠키)을 탈취하는 공격입니다. CSRF는 로그인된 사용자의 권한을 도용해 사용자가 의도치 않은 행위(비밀번호 변경, 결제 등)를 서버에 요청하도록 위조하는 공격입니다.', '웹/HTTP'),
('HTTP 1.1의 HOL Blocking 문제와 HTTP 2.0의 멀티플렉싱 해결책은?', 'HTTP 1.1은 하나의 TCP 연결에서 앞선 요청의 응답이 지연되면 뒤따르는 모든 요청이 큐에 막혀 대기하는 HOL 병목 현상이 있습니다. HTTP 2.0은 데이터를 작은 바이너리 프레임으로 쪼개어 하나의 연결 안에서 여러 스트림을 섞어(Multiplexing) 동시 다발적으로 전송해 이를 해결했습니다.', '웹/HTTP'),

-- ==========================================
-- 7. 네트워크(기타)
-- ==========================================
('DNS(Domain Name System)의 역할과 동작 원리는?', '숫자로 된 복잡한 IP 주소를 사람이 기억하기 쉬운 문자 도메인(naver.com 등)으로 변환해 주는 시스템입니다. 로컬 캐시를 확인하고 없으면 루트 DNS부터 하위 도메인까지 계층적으로 질의하여 최종 IP를 반환받습니다.', '네트워크(기타)'),
('프록시(Proxy) 서버의 역할인 포워드 프록시와 리버스 프록시의 차이는?', '포워드 프록시는 사내망 클라이언트들이 인터넷(외부)으로 나갈 때 거치는 캐싱 및 IP 우회용 서버입니다. 리버스 프록시는 외부 인터넷 요청이 사내망 백엔드 서버로 들어올 때 거치는 앞단 서버(Nginx 등)로, 로드밸런싱과 보안(서버 IP 은닉)을 담당합니다.', '네트워크(기타)'),
('VPN(Virtual Private Network)의 원리와 사용 이유는?', '공중 인터넷 망을 마치 사내 전용선처럼 안전하게 쓰기 위해, 패킷 자체를 암호화하여 터널링(Tunneling)을 구성하는 기술입니다. 원격지 근무자가 회사의 프라이빗 네트워크에 안전하게 접속하기 위해 사용합니다.', '네트워크(기타)'),
('CDN(Content Delivery Network)의 이점은 무엇인가요?', '이미지나 동영상 같은 무거운 정적 콘텐츠를 전 세계에 분산된 엣지(Edge) 캐시 서버에 미리 복사해 둡니다. 사용자가 접속 시 물리적으로 가장 가까운 서버에서 콘텐츠를 내려받게 하여 지연 시간(Latency)을 단축하고 오리진 서버의 트래픽 부하를 방어합니다.', '네트워크(기타)'),
('DDOS 공격 중 SYN Flooding 공격의 원리는 무엇인가요?', '공격자가 TCP 3-Way Handshake의 취약점을 노려, 수많은 가짜 SYN 요청만 보내고 마지막 ACK 응답을 하지 않습니다. 이로 인해 서버의 연결 대기 큐(Backlog Queue)가 가득 차서 정상 사용자의 접속을 받을 수 없게 마비시키는 공격입니다.', '네트워크(기타)'),

-- ==========================================
-- 8. 도커 (기본/이미지/Dockerfile)
-- ==========================================
('도커(Docker) 컨테이너와 기존 가상 머신(VM)의 근본적인 차이는?', 'VM은 하이퍼바이저를 띄우고 무거운 전체 게스트 OS를 설치해야 해 부팅이 오래 걸립니다. 도커 컨테이너는 호스트 OS의 커널을 그대로 공유하며 리눅스 cgroup/namespace로 프로세스 수준의 격리만 하므로 수 초 만에 빠르게 실행되고 리소스 오버헤드가 극히 적습니다.', '도커(기본/이미지)'),
('도커 이미지 레이어(Layer) 아키텍처와 CoW(Copy-on-Write)란?', '이미지는 Dockerfile의 각 명령줄이 독립된 읽기 전용 레이어로 겹겹이 쌓여 만들어집니다. 컨테이너가 실행되면 맨 위에 얇은 쓰기 전용 레이어가 추가되며, 변경 사항은 원본을 건드리지 않고 이 상단 레이어에만 기록(CoW)되어 스토리지 공간을 극적으로 아낍니다.', '도커(기본/이미지)'),
('Dockerfile에서 CMD와 ENTRYPOINT의 차이는 무엇인가요?', 'CMD는 컨테이너 실행 시 기본 인수를 주며 docker run 명령줄에서 다른 명령으로 쉽게 덮어쓸 수 있습니다. ENTRYPOINT는 파라미터를 고정시켜 실행 파일처럼 동작하게 하므로 강제성이 필요한 핵심 데몬 실행에 씁니다.', '도커(기본/이미지)'),
('Dockerfile에서 COPY와 ADD 명령어의 차이는?', 'COPY는 호스트의 로컬 파일이나 디렉터리를 이미지 내로 단순히 복사합니다. ADD는 추가로 외부 URL에서 파일을 다운로드하거나 압축된 tar 파일을 자동으로 풀어서 복사하는 기능이 있으나, 행위의 명확성을 위해 실무에서는 보통 COPY를 권장합니다.', '도커(기본/이미지)'),
('이미지 빌드 시간과 용량을 줄이기 위한 멀티 스테이지 빌드(Multi-stage)란?', '하나의 Dockerfile에 여러 개의 FROM 구문을 두어 빌드용 환경(무거운 컴파일러 등 포함)과 런타임 환경(가벼운 Alpine Linux 등)을 분리합니다. 런타임 이미지에는 이전 단계에서 빌드된 최종 실행 파일만 가져와 복사하므로 이미지 크기가 수십 메가바이트 수준으로 확 줄어듭니다.', '도커(기본/이미지)'),
('도커 빌드 캐시 최적화를 위한 명령어 배치 전략은 무엇인가요?', '도커는 이전 레이어의 코드가 바뀌면 그 아래 명령어의 캐시를 모두 무효화합니다. 따라서 자주 안 바뀌는 환경 설정이나 패키지 설치(npm install) 명령을 위쪽에, 자주 바뀌는 소스 코드 복사(COPY . .)를 맨 아래에 배치해야 후속 빌드 속도가 빨라집니다.', '도커(기본/이미지)'),
('.dockerignore 파일의 목적은 무엇인가요?', 'git의 .gitignore와 유사하게 빌드 컨텍스트를 도커 데몬으로 넘길 때 node_modules, 임시 파일, 민감한 키 파일 등이 이미지에 잘못 섞여 들어가는 것을 막아 이미지 용량을 줄이고 보안을 챙깁니다.', '도커(기본/이미지)'),
('컨테이너 운영 시 불변 인프라(Immutable Infrastructure) 원칙이란?', '실행 중인 컨테이너에 접속해 코드를 직접 수정하는 패치 작업을 절대 하지 않는 것입니다. 변경 사항이 있으면 무조건 새 코드로 이미지를 다시 빌드하고, 이전 파드(컨테이너)를 종료시킨 뒤 새 컨테이너로 통째로 갈아끼우는 방식으로 일관성을 유지합니다.', '도커(기본/이미지)'),
('컨테이너 보안을 위해 root 사용자 권한을 제한해야 하는 이유는?', '컨테이너 내부에서 root 권한을 가지면 해커가 앱 취약점을 뚫었을 때 도커 엔진을 뚫고 호스트 OS까지 장악하는 컨테이너 이스케이프 공격이 가능합니다. Dockerfile 내에서 USER 명령어로 프로세스를 일반 계정으로 낮춰 실행해야 합니다.', '도커(기본/이미지)'),
('Dockerfile에 API 키나 DB 비밀번호를 하드코딩하면 안 되는 이유는?', 'Dockerfile 내용이 이미지 레이어에 평문으로 영구히 각인되어, 이미지를 도커 허브 등 레지스트리에 푸시하면 누구나 레이어 히스토리를 뜯어 민감 정보를 탈취할 수 있습니다. 런타임 시 외부 환경 변수(-e)로 주입해야 합니다.', '도커(기본/이미지)'),

-- ==========================================
-- 9. 도커 (네트워크/스토리지/운영)
-- ==========================================
('도커 볼륨(Named Volumes)과 바인드 마운트(Bind Mounts)를 비교해주세요.', '네임드 볼륨은 도커 엔진이 직접 경로를 관리하여 백업과 이식성이 좋아 DB 데이터베이스 영구 저장에 주로 씁니다. 바인드 마운트는 호스트의 특정 폴더 경로를 직접 매핑하여, 소스 코드를 수정하면 즉시 앱이 리로드되는 개발 환경에 주로 씁니다.', '도커(네트워크/운영)'),
('도커 기본 네트워크 드라이버인 Bridge와 Host의 차이는?', 'Bridge는 단일 호스트 내에서 컨테이너들끼리 격리된 가상망을 쓰며 외부 노출을 위해 포트 매핑(-p)이 필수입니다. Host 모드는 컨테이너가 격리 없이 호스트 서버의 네트워크 인터페이스(IP)를 통째로 공유해 포트 매핑 오버헤드가 없어 최고 성능을 냅니다.', '도커(네트워크/운영)'),
('도커 오버레이(Overlay) 네트워크는 언제 사용하나요?', '도커 스웜(Swarm) 환경처럼 물리적으로 서로 다른 호스트 서버들에 분산 배치된 컨테이너들이, 복잡한 라우터 설정 없이 마치 한 네트워크에 있는 것처럼 자유롭게 통신해야 할 때 사용하는 가상 네트워크 계층입니다.', '도커(네트워크/운영)'),
('컨테이너 리소스 경합을 막기 위한 CPU/메모리 제한 설정법은?', 'docker run 실행 시 --cpus 옵션이나 --memory 플래그를 사용하여, 특정 컨테이너가 버그나 트래픽 폭주로 인해 호스트 서버의 전체 리소스를 독점해버려 다른 서비스까지 죽이는 현상(OOM)을 하드 리밋으로 차단합니다.', '도커(네트워크/운영)'),
('도커 컨테이너 로그가 서버 디스크를 100% 채우는 현상을 막으려면?', '기본 설정 시 컨테이너 로그가 무한정 쌓입니다. 데몬 설정이나 run 옵션에서 log-driver 로테이션 속성을 켜서 max-size(예: 10m)와 max-file(예: 3) 개수를 제한하거나, Fluentd를 통해 외부 엘라스틱서치로 아예 로그를 던져버려야 합니다.', '도커(네트워크/운영)'),
('Docker Compose의 도입 목적과 주요 사용 환경은?', '여러 개의 연관된 컨테이너(웹, API, DB, 캐시)를 매번 긴 명령어로 띄우는 대신, docker-compose.yml 파일 하나에 환경변수와 볼륨, 네트워크 설정을 선언해 두고 명령어 한 번(up)으로 묶어서 실행하는 도구로, 로컬 개발/테스트 환경에서 압도적으로 편리합니다.', '도커(네트워크/운영)'),
('단일 노드용 Docker Compose와 다중 노드용 Docker Swarm의 차이는?', 'Compose는 한 대의 물리 장비 내에서 다중 컨테이너를 통합 관리하는 데 그치지만, Swarm은 여러 대의 물리 장비를 클러스터로 묶어 컨테이너 복제본 스케일링, 라우팅 로드밸런싱, 롤링 업데이트 등을 지원하는 오케스트레이션 도구입니다.', '도커(네트워크/운영)'),
('컨테이너가 기동 직후 Error나 Crash 상태로 뻗을 때 디버깅 순서는?', '1) docker logs <컨테이너ID>로 애플리케이션 출력 에러를 확인합니다. 2) docker inspect로 ExitCode와 OOM(메모리 초과) 여부를 확인합니다. 3) 순식간에 죽어서 로그조차 없다면 ENTRYPOINT를 tail -f /dev/null로 덮어써서 좀비로 살려둔 뒤 docker exec -it로 내부에 셸 진입해 환경을 점검합니다.', '도커(네트워크/운영)'),
('서버 재부팅 시 도커 컨테이너가 자동으로 다시 올라오게 하려면?', '컨테이너 생성 시 --restart always 옵션을 주면 데몬이 시작될 때 컨테이너도 자동으로 구동됩니다. --restart unless-stopped를 주면 관리자가 명시적으로 중지했던 컨테이너만 빼고 자동 복구시켜 운영상 더 안전합니다.', '도커(네트워크/운영)'),
('디스크 용량이 부족할 때 불필요한 도커 리소스를 한 번에 청소하는 명령어는?', 'docker system prune -a --volumes 명령을 사용하면, 현재 실행 중이지 않은 중지된 컨테이너, 사용되지 않는 네트워크, 컨테이너와 연결되지 않은 댕글링 이미지 및 빌드 캐시를 전부 삭제하여 수십 GB의 디스크를 즉각 확보합니다.', '도커(네트워크/운영)'),

-- ==========================================
-- 10. 쿠버네티스 (아키텍처/배포 컨트롤러)
-- ==========================================
('쿠버네티스 마스터 노드(Control Plane)의 4가지 핵심 컴포넌트와 역할은?', '1) Kube-API Server: 클러스터 통신의 유일한 관문이자 인증 처리기. 2) etcd: 클러스터의 모든 상태를 기록하는 단일 진실 공급원(DB). 3) Kube-Scheduler: 파드 배치를 위한 최적의 워커 노드 스케줄링. 4) Kube-Controller-Manager: 리소스의 Desired 상태를 지속적으로 맞추는 역할입니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('워커 노드(Worker Node)의 핵심 컴포넌트인 Kubelet과 Kube-proxy의 역할은?', 'Kubelet은 마스터의 지시를 받아 실제 파드 내부의 컨테이너를 기동하고 헬스를 보고하는 선장(에이전트)입니다. Kube-proxy는 노드의 네트워크 규칙(iptables)을 조작해 Service로 향하는 트래픽이 올바른 파드로 찾아가도록 길을 터주는 통신 장교입니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('쿠버네티스의 파드(Pod)란 무엇이며 컨테이너와 어떻게 다른가요?', '파드는 쿠버네티스에서 배포할 수 있는 가장 작은 논리적 단위입니다. 컨테이너 1개 혹은 강하게 결합된 컨테이너 여러 개를 캡슐화하며, 파드 안의 컨테이너들은 동일한 네트워크 네임스페이스(동일 IP)와 스토리지 볼륨을 공유하여 localhost로 서로 통신합니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('네임스페이스(Namespace)의 목적은 무엇인가요?', '하나의 거대한 물리적 K8s 클러스터를 논리적으로 분할하는 가상 벽입니다. 주로 개발팀(Dev)과 운영팀(Prod)의 환경을 격리하거나, 프로젝트별로 리소스 이름 충돌을 막고 ResourceQuota를 통해 팀별 자원 한도를 통제할 때 씁니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('레플리카셋(ReplicaSet)과 디플로이먼트(Deployment)의 차이점은?', '레플리카셋은 파드의 개수(Replica)가 3개로 설정되었다면 파드가 죽어도 항상 3개를 유지시키는 복제본 관리 기능만 합니다. 디플로이먼트는 이를 감싸 버전 관리, 롤링 업데이트, 장애 시 이전 버전으로의 롤백 등 무중단 배포 라이프사이클 전체를 통제하는 상위 컨트롤러입니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('데몬셋(DaemonSet) 컨트롤러는 어떤 경우에 사용하나요?', '원하는 파드 개수를 무작위 노드에 띄우는 디플로이먼트와 달리, 데몬셋은 클러스터 내의 모든 물리적 워커 노드(또는 특정 라벨을 가진 노드)마다 정확히 1개씩의 파드가 백그라운드로 실행되도록 보장합니다. 주로 노드별 로그 수집기(Fluent Bit)나 모니터링 에이전트 구동에 필수적입니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('데이터베이스나 메시지 큐 배포 시 StatefulSet을 사용해야 하는 이유는?', '디플로이먼트는 파드를 무작위로 삭제/생성하며 상태를 버립니다. 반면 DB는 파드마다 변경되지 않는 고유한 호스트네임 식별자가 필요하고, 재시작되더라도 반드시 이전의 자신의 스토리지(PV)를 찾아 마운트해야 데이터가 유지되므로 StatefulSet의 순차적 스케일링 특성을 써야 합니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('디플로이먼트의 롤링 업데이트 시 maxSurge와 maxUnavailable 옵션의 역할은?', '버전 업데이트 도중의 배포 속도와 가용성을 제어합니다. maxSurge는 교체 과정 중 기존 파드 개수 외에 임시로 더 띄울 수 있는 새 파드의 최대 초과 개수이며, maxUnavailable은 롤아웃 도중 사용할 수 없는 상태가 되어도 괜찮은(가용성 하한선) 기존 파드의 최대 개수입니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('HPA(Horizontal Pod Autoscaler)와 Cluster Autoscaler(CA)의 동작 차이는?', '트래픽 폭주 시 HPA는 CPU나 메모리 부하율을 감지해 논리적인 파드(Pod)의 개수 자체를 늘려버립니다(Scale-out). 이때 노드 자원이 꽉 차 새 파드가 Pending되면 CA가 클라우드(AWS) API를 호출해 물리적인 워커 노드(EC2) 대수 자체를 늘려 파드 배치를 돕습니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('노드의 Taints(테인트)와 파드의 Tolerations(톨러레이션) 메커니즘은?', '테인트는 특정 노드에 묻히는 "얼룩"으로, 일반 파드가 해당 노드에 스케줄링되는 것을 거부합니다. 파드에 이 얼룩을 견딜 수 있는 톨러레이션을 선언해 주어야만 해당 노드에 진입할 수 있습니다. 주로 고가의 GPU 전용 노드에 AI 워크로드만 배치되도록 격리할 때 씁니다.', '쿠버네티스(아키텍처/컨트롤러)'),
('CRD(Custom Resource Definition)와 Operator 패턴이란?', 'CRD는 쿠버네티스의 기본 객체(파드, 서비스 등) 외에 사용자가 자신만의 맞춤형 K8s API 리소스를 정의하는 기능입니다. Operator 패턴은 이 CRD에 사용자 정의 컨트롤러 코드를 결합하여, DB 백업/복구 같은 복잡한 도메인 운영 지식을 쿠버네티스 네이티브 자동화 봇처럼 구현한 것입니다.', '쿠버네티스(아키텍처/컨트롤러)'),

-- ==========================================
-- 11. 쿠버네티스 (네트워크/스토리지/보안/운영)
-- ==========================================
('쿠버네티스 Service 객체의 목적과 종류 3가지(ClusterIP, NodePort, LoadBalancer)의 차이는?', 'Service는 죽었다 살아나며 수시로 IP가 바뀌는 파드들을 논리적으로 묶어 고정된 단일 가상 IP와 도메인을 제공합니다. ClusterIP는 클러스터 내부 통신용, NodePort는 노드의 공인 IP 정적 포트를 통해 외부에서 접속, LoadBalancer는 클라우드의 ALB 등을 연동해 가장 안전하게 대규모 퍼블릭 망에 노출합니다.', '쿠버네티스(네트워크/보안)'),
('인그레스(Ingress)의 목적은 무엇인가요?', '다수의 LoadBalancer 서비스를 띄우면 클라우드 비용이 급증합니다. 인그레스는 클러스터 진입점 역할을 하는 단일 로드밸런서(Nginx 등)를 띄워, URL 경로(/api, /web)나 도메인명(Host) 기반의 세밀한 L7 라우팅을 수행하고 통합 SSL 인증서 복호화를 처리합니다.', '쿠버네티스(네트워크/보안)'),
('네트워크를 통제하는 NetworkPolicy 리소스의 역할은?', '기본적으로 K8s 내의 모든 파드는 서로 통신이 개방되어 있어 해킹 시 횡적 이동(Lateral Movement)에 취약합니다. NetworkPolicy를 설정하면 방화벽처럼 작동하여, 특정 라벨(예: role=frontend)을 가진 파드만 DB 파드(role=db)의 3306 포트로 접근하도록 트래픽을 엄격히 화이트리스트 격리합니다.', '쿠버네티스(네트워크/보안)'),
('PV(PersistentVolume)와 PVC(PersistentVolumeClaim)의 아키텍처적 관계는?', '개발자와 인프라 관리자의 책임을 분리합니다. PV는 관리자가 연동해둔 클라우드(EBS) 인프라의 실제 스토리지 용량입니다. PVC는 앱 개발자가 "SSD 타입 10GB 용량을 달라"고 쿠버네티스에 제출하는 요청서입니다. K8s는 조건이 맞는 PV를 찾아 PVC에 영구 바인딩해 파드에 붙여줍니다.', '쿠버네티스(네트워크/보안)'),
('StorageClass 리소스의 "동적 프로비저닝" 기능이란?', '과거에는 관리자가 수동으로 PV 객체를 100개씩 미리 만들어둬야 했습니다. StorageClass를 선언해두면, 사용자가 PVC 요청서만 제출해도 K8s가 AWS API를 찔러 EBS 볼륨을 즉석에서 자동 생성(동적 프로비저닝)하고 PV를 만들어 연결해 주어 운영 오버헤드가 제로가 됩니다.', '쿠버네티스(네트워크/보안)'),
('ConfigMap과 Secret의 차이, 그리고 Secret 보안 강화를 위한 모범 사례는?', 'ConfigMap은 일반 앱 설정값을 파드에 주입하고, Secret은 DB 비밀번호 등을 Base64로 인코딩해 주입합니다. Base64는 암호화가 아니므로 누구나 디코딩할 수 있어 취약합니다. 실무에서는 K8s 마스터 노드 etcd의 미사용 데이터 암호화 기능을 켜거나, AWS Secrets Manager 등 외부 금고와 연동해야 합니다.', '쿠버네티스(네트워크/보안)'),
('Liveness Probe와 Readiness Probe 설정의 차이점과 중요성은?', 'Liveness는 파드 내 앱이 교착 상태(Deadlock)에 빠졌는지 핑을 쳐서 실패하면 파드 자체를 죽이고 재시작(Restart)시켜 자동 복구합니다. Readiness는 파드가 아직 부팅 중이거나 트래픽을 받을 준비가 안 되었을 때 실패를 반환해, Service의 로드밸런서 엔드포인트에서 이 파드를 임시 제외하여 사용자 에러(502)를 막습니다.', '쿠버네티스(네트워크/보안)'),
('파드가 Pending 상태에 머물 때의 원인과 디버깅 명령어는?', '보통 클러스터 전체에 파드를 띄울 CPU/메모리 리소스가 부족하거나, 노드의 Taint 설정에 파드의 톨러레이션이 맞지 않거나, PVC가 볼륨을 찾지 못한 스케줄링 실패 상태입니다. `kubectl describe pod <파드명>` 명령어 하단의 Events 로그를 보면 스케줄러가 거부한 정확한 사유가 나옵니다.', '쿠버네티스(네트워크/보안)'),
('파드가 CrashLoopBackOff 상태일 때 디버깅하는 방법은?', 'K8s 스케줄링은 성공했으나, 컨테이너 내부의 자바/노드 앱 코드가 에러를 뿜으며 기동 직후 죽고 K8s가 이를 계속 재시작하는 무한 루프 상태입니다. `kubectl logs <파드명>`을 쳐서 앱 에러 로그를 확인해야 하며, 로그가 없다면 `describe` 명령어로 OOMKilled(메모리 초과 강제종료) 여부를 점검합니다.', '쿠버네티스(네트워크/보안)'),
('RBAC(Role-Based Access Control) 권한 제어와 최소 권한의 원칙이란?', 'K8s API에 대한 접근을 통제합니다. ServiceAccount(파드나 사용자)에게 클러스터 전체 관리자 권한을 주지 않고, 오직 특정 네임스페이스(dev) 내에서 특정 리소스(Pod)의 목록 조회(get, list) 작업만 수행할 수 있도록 잘게 쪼갠 Role과 RoleBinding을 부여하여 해킹 피해 범위를 최소화합니다.', '쿠버네티스(네트워크/보안)'),

-- ==========================================
-- 12. 클라우드 아키텍처 (고가용성/네트워크/보안)
-- ==========================================
('VPC 내 퍼블릭 서브넷과 프라이빗 서브넷을 엄격히 분리하는 보안 아키텍처 설계 이유는?', '클라우드 다계층 방어(Defense in Depth)의 핵심입니다. 인터넷과 직접 닿는 퍼블릭 서브넷에는 외부 트래픽을 받는 ALB와 배스천 호스트만 배치합니다. 기업의 심장인 WAS와 데이터베이스(RDS)는 외부 통신망이 끊어진 프라이빗 서브넷 깊숙이 격리하여 디도스나 포트 스캔 등의 직접 침투를 네트워크 레벨에서 원천 차단합니다.', '클라우드(고가용성/보안)'),
('보안 그룹(Security Group)과 네트워크 ACL(NACL)의 동작 방식 차이는?', '보안 그룹은 EC2 인스턴스(컴퓨팅)에 방어막을 치는 Stateful 방화벽으로 허용(Allow) 규칙만 있어 들어온 트래픽의 응답은 자동으로 나갑니다. NACL은 서브넷(네트워크망) 전체를 두르는 Stateless 방화벽으로 허용 및 명시적 차단(Deny) 규칙을 모두 세밀하게 설정할 수 있어 특정 악성 IP를 즉시 블록킹할 때 유리합니다.', '클라우드(고가용성/보안)'),
('클라우드 환경에서 고가용성(High Availability) 아키텍처를 설계하는 방법론은?', '단일 장애점(SPOF)을 제거하는 것입니다. Route 53로 트래픽을 분산하고 다수의 가용 영역(Multi-AZ)에 ALB를 배치합니다. 트래픽 증감에 따라 EC2는 Auto Scaling Group(ASG)을 통해 자동 증설(Scale-out)하며, 데이터베이스는 RDS Multi-AZ 이중화를 통해 메인 DB가 죽어도 스탠바이 DB로 초 단위 자동 페일오버되도록 구성합니다.', '클라우드(고가용성/보안)'),
('RDS Multi-AZ 배포와 Read Replica의 아키텍처적 목적 차이는?', 'Multi-AZ는 다른 데이터센터(AZ)에 동기식으로 데이터를 똑같이 복사해 메인 DB 장애 시 자동으로 승격(Failover)시키는 고가용성/재해복구 목적입니다. Read Replica는 비동기식으로 복제본을 여러 대 만들어 읽기(Select) 트래픽만 전담 처리하게 하여 메인 DB의 쿼리 부하를 확 줄여주는 성능 확장 목적입니다.', '클라우드(고가용성/보안)'),
('재해 복구(DR) 지표인 RPO와 RTO의 정의는 무엇인가요?', 'RPO(복구 시점 목표)는 재해 시 회사가 감수할 수 있는 데이터 손실의 최대 한계선(어느 시점 백업본까지 돌릴 것인가)입니다. RTO(복구 시간 목표)는 장애 발생 직후 시스템을 완전히 수리하여 대고객 서비스가 정상 오픈되기까지 허용되는 최대 시간 허용치입니다.', '클라우드(고가용성/보안)'),
('DR 패턴 중 파일럿 라이트(Pilot Light)와 웜 스탠바이(Warm Standby) 전략의 차이는?', '파일럿 라이트는 가스레인지 불씨처럼 데이터(RDS 동기화)만 재해 리전에 백업해두고 값비싼 앱 서버(EC2)는 꺼둔 상태로 버티다, 재해 시 빠르게 서버를 켭니다(RTO 수십 분 수준). 웜 스탠바이는 앱 서버도 가장 작은 스펙으로 켜두어 즉시 스케일 아웃하므로 RTO가 수 분 이내로 획기적으로 빠르지만 비용이 더 듭니다.', '클라우드(고가용성/보안)'),
('금융권 수준의 DR 패턴인 멀티 사이트 활성/활성(Active/Active) 전략이란?', 'RPO와 RTO가 사실상 0에 수렴하는 극단적 고가용성 패턴입니다. 두 개 이상의 지리적 리전(서울, 도쿄)에 앱 스택을 100% 동일하게 복제 가동하고, Route 53로 사용자 트래픽을 상시 양방향 분산시킵니다. 데이터는 Aurora Global DB로 실시간 동기화하여 한 나라의 데이터센터가 날아가도 서비스 중단이 전혀 없습니다.', '클라우드(고가용성/보안)'),
('AWS CloudTrail과 GuardDuty의 보안 감사 및 위협 탐지 역할은?', 'CloudTrail은 회사 계정 내에서 "누가 언제 어디서 어떤 API 호출(인스턴스 삭제 등)을 했는지" 모든 액션을 로깅하는 블랙박스입니다. GuardDuty는 이 로그와 VPC Flow Logs를 머신러닝으로 감시하여, 새벽에 비정상적인 IP에서 접속해 계정을 탈취하거나 비트코인을 채굴하려는 악성 징후를 실시간 탐지해 경보를 울립니다.', '클라우드(고가용성/보안)'),
('AWS WAF(웹 방화벽)와 AWS Shield의 차이점은 무엇인가요?', 'WAF는 애플리케이션 계층(L7)의 보안 서비스로 ALB나 CloudFront 앞단에서 SQL 인젝션, XSS 같은 악성 코드 삽입 공격이나 악성 봇 트래픽을 세밀한 룰로 차단합니다. Shield는 네트워크/전송 계층(L3/L4)에서 쏟아지는 대규모 인프라 대상의 DDoS 트래픽 공격을 무식하게 방어해 내는 서비스입니다.', '클라우드(고가용성/보안)'),
('클라우드 저장 데이터 보안을 위한 AWS KMS(Key Management Service) 역할은?', '데이터 센터 디스크가 물리적으로 탈취되더라도 해커가 내용을 볼 수 없도록 저장 데이터(Data at Rest)를 암호화합니다. KMS를 통해 S3 버킷, EBS 볼륨, RDS 내부에 저장되는 모든 민감 데이터를 블록 수준에서 투명하게 암호화하며, 이 암호키에 접근할 수 있는 권한 역시 IAM으로 완벽히 통제합니다.', '클라우드(고가용성/보안)'),

-- ==========================================
-- 13. 클라우드 아키텍처 (마이그레이션/비용/서버리스)
-- ==========================================
('레거시 시스템 마이그레이션 전략 중 Rehost(Lift & Shift)의 장단점은?', '온프레미스의 가상 머신(VM)과 아키텍처를 단 1줄의 코드 수정도 없이 AWS EC2로 통째로 들어 옮기는 방식입니다. 마이그레이션 속도가 가장 빠르고 리스크가 적어 데이터센터 임대 만료 시 긴급 대피용으로 좋지만, 클라우드의 핵심인 오토스케일링이나 비용 절감 혜택은 누리기 어렵습니다.', '클라우드(마이그레이션/비용)'),
('마이그레이션 전략 중 Replatform과 Refactor(Re-architect)의 차이는?', 'Replatform은 기본 아키텍처는 유지하되 DB만 RDS 같은 클라우드 관리형 서비스로 갈아 끼워 운영 수고를 덜어내는 방식입니다. Refactor는 고도로 엉킨 모놀리식 코드를 완전히 찢어버리고 AWS Lambda, API Gateway 등을 활용한 서버리스 마이크로서비스로 아예 밑바닥부터 재설계하여 확장성과 비용 효율의 극한을 추구합니다.', '클라우드(마이그레이션/비용)'),
('온프레미스 대용량 RDBMS를 다운타임 없이 클라우드로 마이그레이션하는 파이프라인은?', '초기 데이터 이전과 실시간 동기화를 병행해야 합니다. AWS DMS(Database Migration Service)를 사용해 과거 스냅샷 데이터를 옮기고, 이관 중 발생하는 온프레미스의 추가 변경 사항은 CDC(변경 데이터 캡처) 기능을 통해 클라우드 DB에 실시간 복제합니다. 양쪽 정합성이 100% 일치할 때 트래픽을 클라우드로 컷오버합니다.', '클라우드(마이그레이션/비용)'),
('방대한 미디어 파편 데이터(페타바이트급)를 클라우드로 안전하게 옮기는 방법은?', '일반 인터넷 대역폭으로는 수십 년이 걸리고 탈취 위험이 큽니다. AWS Direct Connect 전용선을 깔아 프라이빗하게 옮기거나, 데이터가 너무 크면 AWS Snowball Edge라는 거대한 물리적 하드디스크가 달린 방폭 가방을 사무실로 배송받아 랜선으로 데이터를 꽉꽉 채운 뒤 AWS 데이터센터로 택배 발송해 S3에 붓는 방식을 씁니다.', '클라우드(마이그레이션/비용)'),
('클라우드 요금 폭탄을 막기 위한 Rightsizing(라이트사이징) 최적화 방법론은?', '성능 모니터링 툴(CloudWatch)을 통해 평균 CPU 사용률이 10% 미만으로 펑펑 놀고 있는 유휴 인스턴스들을 색출합니다. 이후 인스턴스를 아예 중지(Stop)시키거나, 스펙이 한 단계 낮은 인스턴스 타입(예: 4xlarge -> 2xlarge) 혹은 가성비가 좋은 최신 세대(c5 -> c6g) 인스턴스로 사이즈를 다운그레이드하여 낭비 비용을 깎아냅니다.', '클라우드(마이그레이션/비용)'),
('안정적으로 항시 켜두는 서버 인스턴스의 클라우드 컴퓨팅 요금을 대폭 절감하는 방법은?', '트래픽 변동이 없어 24시간 내내 켜두는 베이스라인 워크로드에는 정가(On-Demand) 요금을 내면 손해입니다. 1년 또는 3년 치 사용을 미리 약정하는 RI(예약 인스턴스) 모델이나, 컴퓨팅 사용 금액을 통째로 약정하는 Savings Plans를 구매하면 온디맨드 대비 최대 40~70%의 요금 할인을 적용받을 수 있습니다.', '클라우드(마이그레이션/비용)'),
('스팟 인스턴스(Spot Instance)는 어떤 워크로드에 적합하며 얼마나 비용을 줄이나요?', 'AWS 데이터센터에 남는 유휴 서버를 경매로 빌려 쓰는 방식으로 최대 90% 저렴합니다. 단점은 AWS가 회수가 필요하면 2분 전에 경고하고 강제로 인스턴스를 종료해버립니다. 따라서 언제 꺼져도 타격이 없는(Stateless) 배치 데이터 분석 작업, 이미지 렌더링, CI/CD 테스트 러너 등에 찰떡처럼 쓰입니다.', '클라우드(마이그레이션/비용)'),
('Amazon S3 스토리지 비용을 자동화하여 획기적으로 절약하는 전략은?', '저장 데이터의 엑세스 빈도를 분석하여, 오래된 로그 파일처럼 보관 의무만 있고 잘 열어보지 않는 데이터는 S3 Lifecycle Policy(수명 주기 정책)를 통해 S3 Standard-IA나 아주 저렴한 아카이브용 빙하 스토리지인 Glacier 계층으로 매달 자동 이동되도록 룰을 세팅합니다.', '클라우드(마이그레이션/비용)'),
('서버리스(Serverless) 아키텍처인 AWS Lambda의 비즈니스적 장단점은?', '장점은 개발자가 OS 패치나 EC2 용량 증설을 전혀 고민할 필요 없이 코드 로직에만 집중할 수 있고, 사용자가 몰리면 무한대에 가깝게 자동 확장되며 100ms 단위의 실행 시간에만 요금을 내어 아주 경제적입니다. 단점은 오랫동안 호출이 없다가 갑자기 실행될 때 부팅 시간이 오래 걸리는 콜드 스타트(Cold Start) 지연 현상과 특정 벤더(AWS) 종속성(Lock-in)이 심해진다는 점입니다.', '클라우드(마이그레이션/비용)'),
('Amazon Aurora Serverless는 주로 어떤 환경에서 비용 효율을 극대화하나요?', '신규 런칭한 스타트업 게임이나 간헐적으로 접속자가 폭주하는 이벤트 페이지 등 트래픽 예측이 도저히 불가능한 환경에 최적화되어 있습니다. 평소 접속자가 없을 때는 DB 용량(ACU)이 0에 가깝게 줄어들어 요금을 세이브하다가, 트래픽이 몰리는 순간 DB 엔진 컴퓨팅 자원이 초 단위로 미친 듯이 스케일 업(Scale-up)되어 부하를 방어합니다.', '클라우드(마이그레이션/비용)')
;